// Some portions generated by Codex
package org.eclipse.rdf4j.workbench.util;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.ByteArrayOutputStream;
import java.nio.charset.StandardCharsets;
import java.nio.file.Path;

import org.junit.jupiter.api.Test;

class QueryScriptTraceErrorMessageTest {

	private static final String NODE_SCRIPT = "const fs = require('fs');\n"
			+ "const source = fs.readFileSync(process.argv[1], 'utf8');\n"
			+ "function extractFunction(signature) {\n"
			+ "  const start = source.indexOf(signature);\n"
			+ "  if (start < 0) {\n"
			+ "    throw new Error(signature + ' not found');\n"
			+ "  }\n"
			+ "  let index = start + signature.length;\n"
			+ "  let depth = 1;\n"
			+ "  while (depth > 0 && index < source.length) {\n"
			+ "    const ch = source[index++];\n"
			+ "    if (ch === '{') {\n"
			+ "      depth += 1;\n"
			+ "    } else if (ch === '}') {\n"
			+ "      depth -= 1;\n"
			+ "    }\n"
			+ "  }\n"
			+ "  return source.slice(start + signature.length, index - 1);\n"
			+ "}\n"
			+ "const getErrorMessage = new Function('error', extractFunction('function getErrorMessage(error) {'));\n"
			+ "const fn = new Function('jqXHR', 'textStatus', 'errorThrown',\n"
			+ "  'const getErrorMessage = arguments[3];\\n'\n"
			+ "  + extractFunction('function getExplainErrorMessage(jqXHR, textStatus, errorThrown) {'));\n"
			+ "process.stdout.write(String(fn({\n"
			+ "  responseJSON: {\n"
			+ "    error: {\n"
			+ "      code: 'traceTimeout',\n"
			+ "      message: 'Query trace took too long'\n"
			+ "    }\n"
			+ "  }\n"
			+ "}, 'error', '', getErrorMessage)));\n";

	@Test
	void structuredTraceErrorsShouldReturnMessageText() throws Exception {
		Path scriptPath = Path.of("src/main/webapp/scripts/query.js").toAbsolutePath();
		Process process = new ProcessBuilder("node", "-e", NODE_SCRIPT, scriptPath.toString())
				.redirectErrorStream(true)
				.start();
		ByteArrayOutputStream output = new ByteArrayOutputStream();
		process.getInputStream().transferTo(output);

		assertThat(process.waitFor()).isZero();
		assertThat(output.toString(StandardCharsets.UTF_8)).isEqualTo("Query trace took too long");
	}
}
